def gen(rng, size):
    n = size
    edges = []
    for _ in range(size // 2):
        u = rng.randint(0, n-1)
        v = rng.randint(0, n-1)
        if u != v:
            w = rng.randint(0, 100000)
            edges.append([u, v, w])
    query = []
    for _ in range(20):
        s = rng.randint(0, n-1)
        t = rng.randint(0, n-1)
        if s != t:
            query.append([s, t])
    if not query:
        query = [[0, 1]]
    return [n, edges, query]

