class Solution:
    def minimumCost(self, n: int, edges, query) -> list:
        parent = list(range(n))
        comp_and = [(1 << 17) - 1] * n  # all bits set initially
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b, w):
            ra, rb = find(a), find(b)
            comp_and[ra] &= w
            comp_and[rb] &= w
            if ra != rb:
                parent[rb] = ra
                comp_and[ra] &= comp_and[rb]
        for u, v, w in edges:
            union(u, v, w)
        res = []
        for s, t in query:
            if s == t:
                res.append(0)
            elif find(s) != find(t):
                res.append(-1)
            else:
                res.append(comp_and[find(s)])
        return res

