class Solution:
    def minimumCost(self, n: int, edges, query) -> list:
        parent = list(range(n))
        rank = [0] * n
        comp_and = [(1 << 17) - 1] * n
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b, w):
            ra, rb = find(a), find(b)
            comp_and[ra] &= w
            comp_and[rb] &= w
            if ra == rb:
                return
            if rank[ra] < rank[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            comp_and[ra] &= comp_and[rb]
            if rank[ra] == rank[rb]:
                rank[ra] += 1
        for u, v, w in edges:
            union(u, v, w)
        res = []
        for s, t in query:
            if s == t:
                res.append(0)
            elif find(s) != find(t):
                res.append(-1)
            else:
                res.append(comp_and[find(s)])
        return res

