var minimumCost = function(n, edges, query) {
    const parent = Array.from({length: n}, (_, i) => i);
    const rank = new Array(n).fill(0);
    const compAnd = new Array(n).fill((1 << 17) - 1);
    function find(x) {
        while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
        return x;
    }
    function union(a, b, w) {
        let ra = find(a), rb = find(b);
        compAnd[ra] &= w; compAnd[rb] &= w;
        if (ra === rb) return;
        if (rank[ra] < rank[rb]) { let t = ra; ra = rb; rb = t; }
        parent[rb] = ra;
        compAnd[ra] &= compAnd[rb];
        if (rank[ra] === rank[rb]) rank[ra]++;
    }
    for (const [u, v, w] of edges) union(u, v, w);
    return query.map(([s, t]) => {
        if (s === t) return 0;
        if (find(s) !== find(t)) return -1;
        return compAnd[find(s)];
    });
};
